// Render **bold** and *italic* markdown inline.
function renderBold(text: string) {
  const parts: Array<{ t: string; b?: boolean; i?: boolean }> = [];
  const regex = /(\*\*[^*]+\*\*|\*[^*]+\*)/g;
  let last = 0;
  for (const m of text.matchAll(regex)) {
    const idx = m.index ?? 0;
    if (idx > last) parts.push({ t: text.slice(last, idx) });
    const tok = m[0];
    if (tok.startsWith('**')) parts.push({ t: tok.slice(2, -2), b: true });
    else parts.push({ t: tok.slice(1, -1), i: true });
    last = idx + tok.length;
  }
  if (last < text.length) parts.push({ t: text.slice(last) });
  return parts.map((p, i) =>
    p.b ? <strong key={i}>{p.t}</strong> : p.i ? <em key={i}>{p.t}</em> : <span key={i}>{p.t}</span>
  );
}

function StarsRow({ n = 5, size = 16 }: { n?: number; size?: number }) {
  return (
    <div className="inline-flex text-brand-gold">
      {Array.from({ length: n }).map((_, i) => (
        <StarIcon key={i} size={size} fill="currentColor" stroke="none" />
      ))}
    </div>
  );
}

